import {
    Box,
    Button,
    Dialog,
    DialogContent,
    DialogTitle,
    FormControl,
    InputLabel,
    MenuItem,
    Select,
    TextField,
    Typography,
    IconButton,
    Autocomplete,
    Chip,
    Checkbox,
    FormControlLabel
  } from "@mui/material";
  import CloseIcon from "@mui/icons-material/Close";
  import React, { useEffect, useState, useRef } from "react";
  import { useNavigate } from "react-router-dom";
  import { useAppDispatch, useAppSelector } from "src/assets/hooks";
import { academicTests, gradeScaleOptions, languageTests } from "src/assets/constants/misc";
import { editProfile, getRecommendations } from "src/services";
import { setPopup } from "src/store/Slices/popupSlice";
import { countryList } from "src/assets/menu";
import { setRecommendEditData } from 'src/store/Slices/recommendEditSlice';
import { courseList } from "src/assets/constants/courseList";
import { setRecommended, setRecommendationsLoading, setRecommendationsComplete } from "src/store/Slices/recommendations";
import { setProfile } from "src/store/Slices/profile";

  
  interface Criterion {
    label: string;
    data: {
      value: any;
      editLink?: string;
    };
  }
  
  interface RecommendationEditModalProps {
    open: boolean;
    onClose: () => void;
    data: any[];
    onSubmit?: (updatedData: Record<string, string>) => void;
    //courseList: string[]; 
  }

  
  const testOptions = [
    { label: "IELTS", value: "IELTS" },
    { label: "TOEFL", value: "TOEFL" },
    { label: "Duolingo", value: "Duolingo" },
    { label: "PTE", value: "PTE" },
  ];
  
  const testOptions1 = [
    { label: "GRE", value: "GRE" },
    { label: "GMAT", value: "GMAT" },
    { label: "SAT", value: "SAT" },
    { label: "ACT", value: "ACT" },
  ];
  
  const outOff=[
    {label:'Percentage out of 100',value:100},
    {label:'CGPA out of 10',value:10},
    {label:"CGPA out of 7",value:7},
    {label:"CGPA out of 5",value:5},
    {label:"CGPA out of 4",value:4}
  ]
  
  const RecommendationEditModal = ({
    open,
    onClose,
    data,
    onSubmit,
  }: RecommendationEditModalProps) => {
    const navigate = useNavigate();
    const dispatch = useAppDispatch();
    const recommendations = useAppSelector((state) => state.recommendations);
    const recommendEditData = useAppSelector((state) => state.recommendEdit);
    const criteria: Criterion[] = recommendations?.data?.criteria || [];
    const profile = useAppSelector((state) => state.profile);
    const testScoresState = useAppSelector((state) => state.testscores);
    const educationState = useAppSelector((state) => state.educationhistory);
    const preferencesState = useAppSelector((state) => state.preferences);
    const [formData, setFormData] = useState<Record<string, any>>({});
    const lastCriteriaRef = useRef<string>('');
    const hasInitializedRef = useRef(false);
    

   useEffect(() => {
    console.log("Working 333",recommendEditData)
    // Create a string identifier for current criteria to detect changes
    const criteriaKey = criteria.length > 0 
      ? JSON.stringify(criteria.map(c => ({ label: c.label, value: c.data.value })))
      : '';
    console.log("Workinnggg",criteriaKey,hasInitializedRef)
    // Skip if criteria hasn't changed and we've already initialized (prevents infinite loop)

    // if (criteriaKey === lastCriteriaRef.current && hasInitializedRef.current) {
    //   console.log("Workinnggg 000")
    //   return;
    // }
    
    // Update the ref with current criteria
    lastCriteriaRef.current = criteriaKey;
    
    const findLanguageTest = (label: string) =>
      languageTests.find(
        (test) => test.fullForm === label || test.shortForm === label
      );
    const findAcademicTest = (label: string) =>
      academicTests.find(
        (test) => test.fullForm === label || test.shortForm === label
      );
      console.log("Working 222",criteria)
    // Prioritize criteria data if available, otherwise use existing Redux data
    if (criteria && criteria.length > 0) {
      const gpaData = criteria.find((item) => item.label === "GPA")?.data.value;
      const [score, maxScore] = gpaData ? gpaData.split("/").map((s: string) => s.trim()) : ['', ''];
      const englishCriterion = criteria.find((item) => findLanguageTest(item.label));
      const academicCriterion = criteria.find((item) => findAcademicTest(item.label));
      // Check if user has already indicated they don't want to take tests (from Redux)
      const userNotPlanningLanguage = false//recommendEditData?.isPlanningToTakeLanguageTest === false;
      const userNotPlanningAcademic = false//recommendEditData?.isPlanningToTakeAcademicTest === false;
      const isPlanningLanguage = !!englishCriterion && !userNotPlanningLanguage;
      const isPlanningAcademic = !!academicCriterion && !userNotPlanningAcademic;
      let temp = {
        studyLevel: criteria.find((item) => item.label === "StudyLevel")?.data.value || 'Bachelors',
        bachelorsScore: score,
        gradeScale: gradeScaleOptions.find((item) => item.maxScore.toString() === maxScore)?.label || '',
        backlogs: criteria.find((item) => item.label === "Backlogs")?.data.value || '',
        englishTestType: isPlanningLanguage ? (findLanguageTest(englishCriterion?.label || "")?.shortForm || '') : '',
        englishTestScore: isPlanningLanguage ? (englishCriterion?.data.value || '') : '',
        academicTestType: isPlanningAcademic ? (findAcademicTest(academicCriterion?.label || "")?.shortForm || '') : '',
        academicTestScore: isPlanningAcademic ? (academicCriterion?.data.value || '') : '',
        isPlanningToTakeLanguageTest: isPlanningLanguage,
        isPlanningToTakeAcademicTest: isPlanningAcademic,
        country: (() => {
          const countryValue = criteria.find((item) => item.label === "Country")?.data.value;
          if (!countryValue) return [];
          return Array.isArray(countryValue) ? countryValue : [countryValue];
        })(),
        subCategory: criteria.find((item) => item.label === "SubCategory")?.data.value?.map((item: string) => ({ label: item, value: item })) || []
      };

      console.log("FORM FOUND",temp)
      setFormData(temp);
      // Store in Redux
      dispatch(setRecommendEditData(temp));
      hasInitializedRef.current = true;
    } else if (!criteriaKey) {
      // If no criteria, use recommendEditData or default values
      if (recommendEditData && Object.keys(recommendEditData).length > 0) {
        // Use existing Redux data if no criteria available
        // Ensure boolean fields are properly set (not undefined)
        // Clear test type and score if user is not planning to take the tests
        const normalizedData = {
          ...recommendEditData,
          isPlanningToTakeLanguageTest: recommendEditData.isPlanningToTakeLanguageTest ?? false,
          isPlanningToTakeAcademicTest: recommendEditData.isPlanningToTakeAcademicTest ?? false,
          // Clear test fields if not planning to take
          englishTestType: (recommendEditData.isPlanningToTakeLanguageTest ?? false) ? (recommendEditData.englishTestType || '') : '',
          englishTestScore: (recommendEditData.isPlanningToTakeLanguageTest ?? false) ? (recommendEditData.englishTestScore || '') : '',
          academicTestType: (recommendEditData.isPlanningToTakeAcademicTest ?? false) ? (recommendEditData.academicTestType || '') : '',
          academicTestScore: (recommendEditData.isPlanningToTakeAcademicTest ?? false) ? (recommendEditData.academicTestScore || '') : '',
        };
        setFormData(normalizedData);
      } else {
        // Initialize with default values if no criteria and no Redux data
        const defaultData = {
          studyLevel: 'Bachelors',
          bachelorsScore: '',
          gradeScale: '',
          backlogs: '',
          englishTestType: '',
          englishTestScore: '',
          academicTestType: '',
          academicTestScore: '',
          isPlanningToTakeLanguageTest: false,
          isPlanningToTakeAcademicTest: false,
          country: [],
          subCategory: []
        };
        setFormData(defaultData);
      }
      hasInitializedRef.current = true;
    }
    
    // Reset initialization flag when modal closes to allow re-initialization on next open
    if (!open) {
      hasInitializedRef.current = false;
      lastCriteriaRef.current = '';
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [criteria, dispatch, open]);

  
    const handleChange = (field: string, value: any) => {
      const newData = {
        ...formData,
        [field]: value,
      };
      setFormData(newData);
      // Update Redux store with the entire form data to maintain consistency
      dispatch(setRecommendEditData(newData));
    };

    const validateScores = () => {
      let error = '';
      
      // Academic Test Validation - only validate if planning to take
      if (formData["isPlanningToTakeAcademicTest"] === true) {
        if (!formData["academicTestType"] || formData["academicTestType"] === "") {
          error = "Please select an academic test type";
          return error;
        }
        const selectedTest = testOptions1.find(opt => opt.label === formData["academicTestType"]);
        const academicScore = formData["academicTestScore"];
        
        // Check if score is provided when required
        if (!academicScore || academicScore === "") {
          error = "Academic test score is required";
          return error;
        }
        
        const scoreNum = Number(academicScore);
        if (selectedTest?.label === "GRE") {
          if (scoreNum < 260 || scoreNum > 340 || scoreNum % 1 !== 0) {
            error = "GRE score must be between 260 and 340 ";
          }
        } else if (selectedTest?.label === "GMAT") {
          if (scoreNum < 200 || scoreNum > 800 || scoreNum % 5 !== 0) {
            error = "GMAT score must be between 200 and 800";
          }
        } else if (selectedTest?.label === "SAT") {
          if (scoreNum < 200 || scoreNum > 1600 || scoreNum % 1 !== 0) {
            error = "SAT score must be between 200 and 1600";
          }
        } else if (selectedTest?.label === "ACT") {
          if (scoreNum < 1 || scoreNum > 36 || scoreNum % 1 !== 0) {
            error = "ACT score must be between 1 and 36 ";
          }
        }
      }
      
      // English Test Validation - only validate if planning to take
      if (formData["isPlanningToTakeLanguageTest"] === true) {
        if (!formData["englishTestType"] || formData["englishTestType"] === "") {
          error = "Please select an English test type";
          return error;
        }
        const selectedEngTest = testOptions.find(opt => opt.label === formData["englishTestType"]);
        const englishScore = formData["englishTestScore"];
        
        // Check if score is provided when required
        if (!englishScore || englishScore === "") {
          error = "English test score is required";
          return error;
        }
        
        const scoreNum = Number(englishScore);
        if (selectedEngTest?.label === "IELTS") {
          const isHalfStep = Math.abs(scoreNum * 10) % 5 === 0;
          if (scoreNum < 0 || scoreNum > 9 || !isHalfStep) {
            error = "IELTS score must be between 0 and 9 ";
          }
        } else if (selectedEngTest?.label === "TOEFL") {
          if (scoreNum < 0 || scoreNum > 120 || scoreNum % 1 !== 0) {
            error = "TOEFL score must be between 0 and 120";
          }
        } else if (selectedEngTest?.label === "Duolingo") {
          if (scoreNum < 0 || scoreNum > 160 || scoreNum % 1 !== 0) {
            error = "Duolingo score must be between 0 and 160";
          }
        } else if (selectedEngTest?.label === "PTE") {
          if (scoreNum < 0 || scoreNum > 90 || scoreNum % 1 !== 0) {
            error = "PTE score must be between 0 and 90";
          }
        }
      }
      // Grade Scale Validation
      const gradeScale = formData["gradeScale"];
      const bachelorsScore = Number(formData["bachelorsScore"]);
      if (gradeScale === "Percentage out of 100") {
        if (bachelorsScore < 0 || bachelorsScore > 100) {
          error = "Percentage must be between 0 and 100";
        }
      } else if (gradeScale === "CGPA out of 10") {
        if (bachelorsScore < 0 || bachelorsScore > 10) {
          error = "CGPA out of 10 must be between 0 and 10";
        }
      } else if (gradeScale === "CGPA out of 7") {
        if (bachelorsScore < 0 || bachelorsScore > 7) {
          error = "CGPA out of 7 must be between 0 and 7";
        }
      } else if (gradeScale === "CGPA out of 5") {
        if (bachelorsScore < 0 || bachelorsScore > 5) {
          error = "CGPA out of 5 must be between 0 and 5";
        }
      } else if (gradeScale === "CGPA out of 4") {
        if (bachelorsScore < 0 || bachelorsScore > 4) {
          error = "CGPA out of 4 must be between 0 and 4";
        }
      }
      return error;
    };

    const normalizeRecommendations = (response: any) => {
      if (!response) return null;
      if (response?.criteria !== undefined || Array.isArray(response?.data)) return response;
      if (response?.data?.criteria !== undefined || Array.isArray(response?.data?.data)) return response.data;
      return response?.data ?? response;
    };

    const submit=async ()=>{
      const validationError = validateScores();
      if (validationError) {
        dispatch(setPopup({
          show: true,
          data: {
            container: {
              name: "error",
              data: validationError,
              dimensions: { width: "30%", height: "40%", show: "none" },
            },
            type: "custom",
          },
        }));
        return;
      }

      const profileData = profile?.data;
      const profileTestsFromProfile = profileData?.tests;
      const profileTests = Array.isArray(profileTestsFromProfile)
        ? [...profileTestsFromProfile]
        : (Array.isArray(testScoresState?.data) ? [...testScoresState.data] : []);
      const currentEducation = profileData?.education || educationState?.data || {};
      const currentPreference = profileData?.preference || preferencesState?.data || {};

      let updatedTests = [...profileTests];
        
        // Handle Language Test
      if (formData["isPlanningToTakeLanguageTest"] === true && formData["englishTestType"] && formData["englishTestScore"]) {
          const languageTestName = languageTests.find((item)=>item.shortForm===formData["englishTestType"])?.fullForm;
          if (languageTestName) {
            let current = updatedTests.findIndex((item)=>item.name===languageTestName);
            if(current!==-1) {
              updatedTests[current]={...updatedTests[current],scores:[...updatedTests[current].scores.filter((item)=>item.description!=="Total"),{
                description:"Total",
                count:formData["englishTestScore"]
              }]};
            } else {
              updatedTests.push({
                name: languageTestName,
                type:"language",
                scores:[{
                  description:"Total",
                  count:formData["englishTestScore"]
                }]
              } as any);
            }
          }
        } else {
          // Remove language tests if not planning to take
          updatedTests = updatedTests.filter((item) => 
            !languageTests.find((item2)=>item2.fullForm===item.name)
          );
        }
        
        // Handle Academic Test
      if (formData["isPlanningToTakeAcademicTest"] === true && formData["academicTestType"] && formData["academicTestScore"]) {
          const academicTestName = academicTests.find((item)=>item.shortForm===formData["academicTestType"])?.fullForm;
          if (academicTestName) {
            let current = updatedTests.findIndex((item)=>item.name===academicTestName);
            if(current!==-1) {
              updatedTests[current]={...updatedTests[current],scores:[...updatedTests[current].scores.filter((item)=>item.description!=="Total"),{
                description:"Total",
                count:formData["academicTestScore"]
              }]};
            } else {
              updatedTests.push({
                name: academicTestName,
                type:'academic',
                scores:[{
                  description:"Total",
                  count:formData["academicTestScore"]
                }]
              } as any);
            }
          }
        } else {
          // Remove academic tests if not planning to take
          updatedTests = updatedTests.filter((item) => 
            !academicTests.find((item2)=>item2.fullForm===item.name)
          );
        }

      const selectedGradeScale = gradeScaleOptions.find(
        (item)=>item.label===formData["gradeScale"]
      );
      const selectedSubCategories = Array.isArray(formData["subCategory"])
        ? formData["subCategory"].map((item:any)=>typeof item === "string" ? item : item?.value).filter(Boolean)
        : [];
      const selectedCountries = Array.isArray(formData["country"])
        ? formData["country"].filter(Boolean)
        : [];

      const temp={
        tests:updatedTests,
        education:{
          ...currentEducation,
          underGraduation:{
            ...(currentEducation?.underGraduation || {}),
            totalScore:Number(formData["bachelorsScore"] || 0),
            backlogs:Number(formData["backlogs"] || 0),
            maxScore:selectedGradeScale?.maxScore,
            gradingSystem:selectedGradeScale?.value
          }
        },
        preference:{
          ...currentPreference,
          subCategory:selectedSubCategories,
          country:selectedCountries
        }
      };

      onClose();
      dispatch(setRecommendationsLoading());

      try {
        const response = await editProfile(temp);
        const updatedProfile = response?.data?.data;
        if (updatedProfile) {
          dispatch(setProfile(updatedProfile));
        }

        let normalizedRecommendations = normalizeRecommendations(
          updatedProfile?.recommendations || response?.data?.data?.recommendations
        );

        // Fallback for backends that don't return recommendations from profile update.
        if (!normalizedRecommendations || !Array.isArray(normalizedRecommendations?.data)) {
          const recommendationsResponse = await getRecommendations({});
          normalizedRecommendations = normalizeRecommendations(recommendationsResponse);
        }

        if (normalizedRecommendations) {
          dispatch(setRecommended(normalizedRecommendations));
          onSubmit?.(formData as Record<string, string>);
          dispatch(
            setPopup({
              show: true,
              data: {
                container: {
                  name: "success",
                  data: "Criteria Updated Successfully! Recommendations have been regenerated with your new preferences.",
                  dimensions: {
                    width: "35%",
                    height: "40%",
                    show: "none"
                  },
                },
                type: "custom",
              },
            })
          );
          return;
        }

        throw new Error("No recommendations data received");
      } catch (error) {
        dispatch(setRecommendationsComplete());
        dispatch(
          setPopup({
            show: true,
            data: {
              container: {
                name: "error",
                data: "Unable to update profile recommendations. Please try again.",
                dimensions: {
                  width: "35%",
                  height: "40%",
                  show: "none"
                },
              },
              type: "custom",
            },
          })
        );
      }
    }

  
    return (
      <Dialog open={open} onClose={onClose} fullWidth maxWidth="sm">
        <DialogTitle sx={{ 
          fontWeight: 600, 
          fontSize: "1.2rem", 
          pr: 4,
          borderBottom: "1px solid #eee",
          pb: 2
        }}>
          Your recommendations are based on:
          <IconButton
            onClick={onClose}
            sx={{ position: "absolute", top: 12, right: 12 }}
          >
            <CloseIcon />
          </IconButton>
        </DialogTitle>
  
        <DialogContent sx={{ mt: 2 }}>
          <Box display="flex" flexDirection="column" gap={3}>
            {/* Bachelors Score Section */}
            <Box>
              <Typography variant="subtitle1" fontWeight={500} gutterBottom>
                {formData["studyLevel"] || 'Bachelors'}
              </Typography>
              <Box display="flex" gap={2}>
                <TextField
                  size="small"
                  label="Enter Score"
                  value={formData["bachelorsScore"] || ""}
                  onChange={(e) => handleChange("bachelorsScore", e.target.value)}
                  sx={{ flex: 1 }}
                />
                <FormControl size="small" sx={{ flex: 1 }}>
                  <InputLabel>Grade scale</InputLabel>
                  <Select
                    label="Grade scale"
                    value={formData["gradeScale"] || ""}
                    onChange={(e) => handleChange("gradeScale", e.target.value)}
                  >
                    {outOff.map((item) => (
                      <MenuItem key={item.value} value={item.label}>
                        {item.label}
                      </MenuItem>
                    ))}
                  </Select>
                </FormControl>
                <TextField
                  size="small"
                  label="Backlogs"
                  value={formData["backlogs"] || ""}
                  onChange={(e) => handleChange("backlogs", e.target.value)}
                  sx={{ flex: 1 }}
                />
              </Box>
            </Box>

            {/* English Test Section */}
            <Box>
              <Typography variant="subtitle1" fontWeight={500} gutterBottom>
                English proficiency test
              </Typography>
              <Box display="flex" gap={2} alignItems="center" flexWrap={{ xs: "wrap", md: "nowrap" }}>
                <FormControl size="small" sx={{ flex: 1 }}>
                  <InputLabel>Select test</InputLabel>
                  <Select
                    label="Select test type"
                    value={formData["englishTestType"] || ""}
                    onChange={(e) => handleChange("englishTestType", e.target.value)}
                    disabled={formData["isPlanningToTakeLanguageTest"] === false || formData["isPlanningToTakeLanguageTest"] === undefined}
                  >
                    {testOptions.map((option) => (
                      <MenuItem key={option.value} value={option.label}>
                        {option.label}
                      </MenuItem>
                    ))}
                  </Select>
                </FormControl>
                <TextField
                  size="small"
                  label="Enter score"
                  value={formData["englishTestScore"] || ""}
                  onChange={(e) => handleChange("englishTestScore", e.target.value)}
                  disabled={formData["isPlanningToTakeLanguageTest"] === false || formData["isPlanningToTakeLanguageTest"] === undefined}
                  required={formData["isPlanningToTakeLanguageTest"] === true && !!formData["englishTestType"]}
                  sx={{ 
                    width: (formData["isPlanningToTakeLanguageTest"] === false || formData["isPlanningToTakeLanguageTest"] === undefined) ? '120px' : undefined,
                    flex: (formData["isPlanningToTakeLanguageTest"] === false || formData["isPlanningToTakeLanguageTest"] === undefined) ? 'none' : 1
                  }}
                />
                <FormControlLabel
                  control={
                    <Checkbox
                      checked={formData["isPlanningToTakeLanguageTest"] === false || formData["isPlanningToTakeLanguageTest"] === undefined}
                      onChange={(e) => {
                        const isNotPlanning = e.target.checked;
                        // Update the state: if checkbox is checked, isPlanningToTakeLanguageTest = false
                        const newData = {
                          ...formData,
                          isPlanningToTakeLanguageTest: !isNotPlanning,
                          englishTestType: "",
                          englishTestScore: ""
                        };
                        setFormData(newData);
                        dispatch(setRecommendEditData(newData));
                      }}
                      sx={{ mt: 0 }}
                    />
                  }
                  label="Not planning to take"
                  sx={{ mt: 0 }}
                />
              </Box>
            </Box>

            {/* GRE/GMAT Section */}
            <Box>
              <Typography variant="subtitle1" fontWeight={500} gutterBottom>
                GRE, GMAT, SAT, ACT
              </Typography>
              <Box display="flex" gap={2} alignItems="center" flexWrap={{ xs: "wrap", md: "nowrap" }}>
                <FormControl size="small" sx={{ flex: 1 }}>
                  <InputLabel>Select test type</InputLabel>
                  <Select
                    label="Select test type"
                    value={formData["academicTestType"] || ""}
                    onChange={(e) => handleChange("academicTestType", e.target.value)}
                    disabled={formData["isPlanningToTakeAcademicTest"] === false || formData["isPlanningToTakeAcademicTest"] === undefined}
                  >
                    {testOptions1.map((option) => (
                      <MenuItem key={option.value} value={option.label}>
                        {option.label}
                      </MenuItem>
                    ))}
                  </Select>
                </FormControl>
                <TextField
                  size="small"
                  label="Enter score"
                  value={formData["academicTestScore"] || ""}
                  onChange={(e) => handleChange("academicTestScore", e.target.value)}
                  disabled={formData["isPlanningToTakeAcademicTest"] === false || formData["isPlanningToTakeAcademicTest"] === undefined}
                  required={formData["isPlanningToTakeAcademicTest"] === true && !!formData["academicTestType"]}
                  sx={{ 
                    width: (formData["isPlanningToTakeAcademicTest"] === false || formData["isPlanningToTakeAcademicTest"] === undefined) ? '120px' : undefined,
                    flex: (formData["isPlanningToTakeAcademicTest"] === false || formData["isPlanningToTakeAcademicTest"] === undefined) ? 'none' : 1
                  }}
                />
                <FormControlLabel
                  control={
                    <Checkbox
                      checked={formData["isPlanningToTakeAcademicTest"] === false || formData["isPlanningToTakeAcademicTest"] === undefined}
                      onChange={(e) => {
                        const isNotPlanning = e.target.checked;
                        // Update the state: if checkbox is checked, isPlanningToTakeAcademicTest = false
                        const newData = {
                          ...formData,
                          isPlanningToTakeAcademicTest: !isNotPlanning,
                          academicTestType: "",
                          academicTestScore: ""
                        };
                        setFormData(newData);
                        dispatch(setRecommendEditData(newData));
                      }}
                      sx={{ mt: 0 }}
                    />
                  }
                  label="Not planning to take"
                  sx={{ mt: 0 }}
                />
              </Box>
            </Box>

            {/* Country Selection */}
            <Box>
              <Typography variant="subtitle1" fontWeight={500} gutterBottom>
                Select Country
              </Typography>
              <Autocomplete
                multiple
                size="small"
                options={countryList}
                getOptionLabel={(option) => option}
                value={formData["country"] || []}
                onChange={(event, value) => handleChange("country", value)}
                renderInput={(params) => (
                  <TextField
                    {...params}
                    placeholder="Search countries"
                    sx={{
                      '& .MuiOutlinedInput-root': {
                        padding: '4px 8px'
                      }
                    }}
                  />
                )}
                renderTags={(value, getTagProps) =>
                  value.map((option, index) => (
                    <Chip
                      {...getTagProps({ index })}
                      label={option}
                      size="small"
                      sx={{
                        bgcolor: 'primary.light',
                        color: 'white',
                        '& .MuiChip-deleteIcon': {
                          color: 'white'
                        }
                      }}
                    />
                  ))
                }
                ListboxProps={{
                  style: { maxHeight: 200 }
                }}
              />
            </Box>

            {/* Program Selection */}
            <Box>
              <Typography variant="subtitle1" fontWeight={500} gutterBottom>
                What program would you like to pursue?
              </Typography>
              <Autocomplete
                multiple
                size="small"
                options={courseList}
                getOptionLabel={(option) => option.label}
                value={formData["subCategory"] || []}
                onChange={(event, value) => handleChange("subCategory", value)}
                renderInput={(params) => (
                  <TextField
                    {...params}
                    placeholder="Search programs"
                    sx={{
                      '& .MuiOutlinedInput-root': {
                        padding: '4px 8px'
                      }
                    }}
                  />
                )}
                renderTags={(value, getTagProps) =>
                  value.map((option, index) => (
                    <Chip
                      {...getTagProps({ index })}
                      label={option.label}
                      size="small"
                      sx={{
                        bgcolor: 'primary.light',
                        color: 'white',
                        '& .MuiChip-deleteIcon': {
                          color: 'white'
                        }
                      }}
                    />
                  ))
                }
                ListboxProps={{
                  style: { maxHeight: 200 }
                }}
              />
            </Box>

            {/* Action Buttons */}
            <Box sx={{ 
              display: 'flex', 
              flexDirection: 'column', 
              alignItems: 'center',
              gap: 1,
              mt: 2 
            }}>
              <Button
                variant="contained"
                sx={{
                  width: '30%',
                  backgroundColor: "#F48438",
                  color: "#fff",
                  borderRadius: "999px",
                  py: 1.2,
                  fontWeight: 600,
                  textTransform: "none",
                  "&:hover": {
                    backgroundColor: "#F48438",
                  },
                }}
                onClick={() => {
                  submit();
                }}
              >
                Continue
              </Button>

                                            <Typography variant="body2" sx={{ color: "#555", textAlign: "center" }}>
                 Want to edit further?{" "}
                 <Box
                   component="span"
                   onClick={() => {
                     // Clear the user-profile data from localStorage to start fresh
                     localStorage.removeItem("user-profile");
                     
                     // Navigate to the initial step (Start page)
                     navigate("/startpage");
                   }}
                   sx={{
                     textTransform: "none",
                     fontWeight: 600,
                     color: 'primary.main',
                     cursor: 'pointer',
                     '&:hover': {
                       color: 'primary.dark',
                     },
                   }}
                 >
                   Edit
                 </Box>
               </Typography>
            </Box>
          </Box>
        </DialogContent>
      </Dialog>
    );
  };
  
  export default RecommendationEditModal;
  